import aiocoap
from aiocoap import Context, Message, Code

async def handle_get(request):
    if request.uri_path == ('sensors', 'temp'):
        response = Message(code=Code.Content, payload=b'25.3')
    elif request.uri_path == ('actuators', 'light'):
        response = Message(code=Code.Content, payload=b'ON')
    else:
        response = Message(code=Code.NotFound)
    return response

async def handle_put(request):
    if request.uri_path == ('actuators', 'light'):
        if b'OFF' in request.payload:
            response = Message(code=Code.Changed, payload=b'Light OFF')
        elif b'ON' in request.payload:
            response = Message(code=Code.Changed, payload=b'Light ON')
        else:
            response = Message(code=Code.BadRequest)
    else:
        response = Message(code=Code.NotFound)
    return response

async def main():
    context = await Context.create_server_context()
    await context.request(Message(code=Code.GET, uri='coap://localhost/sensors/temp')).response
    await context.request(Message(code=Code.PUT, uri='coap://localhost/actuators/light', payload=b'ON')).response
    await context.request(Message(code=Code.PUT, uri='coap://localhost/actuators/light', payload=b'OFF')).response

if __name__ == "__main__":
    import asyncio
    asyncio.run(main())